再说说其他办法，利用/proc目录符号链接绕过include_once()，方法来自Tel佬的博客，具体原理可参考这篇文章：php源码分析 require_once 绕过不能重复包含文件的限制，用上面的脚本我们读取index.php源码，可以更清晰的看出来
&lt;?php
error_reporting(0);

include &#39;flag.php&#39;;

if(!isset($_GET[&#39;file&#39;])) &#123;
    header(&#39;Location:&#x2F;index.php?file&#x3D;&#39;);
&#125; else &#123;
    $file &#x3D; $_GET[&#39;file&#39;];

    if (!preg_match(&#39;&#x2F;\.\.|data|input|glob|global|var|dict|gopher|file|http|phar|localhost|\?|\*|\~|zip|7z|compress&#x2F;is&#39;, $file)) &#123;
        include_once $file;
    &#125; else &#123;
        die(&#39;error.&#39;);
    &#125;
