@app.route(&#39;&#x2F;upload&#39;, methods&#x3D;[&#39;POST&#39;])
def upload():
    if &#39;file&#39; not in request.files:
        return redirect(&#39;&#x2F;&#39;)
    file &#x3D; request.files[&#39;file&#39;]
    if &quot;.&quot; in file.filename:  # 检查上传的文件名是否含有点号，即过滤了后缀名
