# -*- coding: utf-8 -*-
# @Author : ph0ebus
import os


def foo():
    File &#x3D; &quot;Bossanova.wav&quot;  # steghide加密的文件
    errors &#x3D; [&#39;could not extract&#39;, &#39;steghide --help&#39;, &#39;Syntax error&#39;]  # 密钥错误的情况
    cmdFormat &#x3D; r&#39;steghide extract -sf &quot;%s&quot; -p &quot;%d&quot; 2&gt;&amp;1&#39;  # steghide解密，2&gt;&amp;1是让标准错误输出重定向到标准输出，否则后续读取不到错误信息
